{"command": "python3 << 'PYEOF'
import openpyxl
wb = openpyxl.load_workbook('/root/test-supply.xlsx')
for sheet_name in wb.sheetnames:
    ws = wb[sheet_name]
    print(f"\n=== Sheet: {sheet_name} ===")
    print(f"Dimensions: {ws.dimensions}")
    # Print first 30 rows, first 15 cols
    for row in ws.iter_rows(min_row=1, max_row=min(30, ws.max_row), min_col=1, max_col=min(15, ws.max_column), values_only=False):
        vals = []
        for cell in row:
            v = cell.value
            if v is None:
                vals.append("")
            else:
                vals.append(str(v)[:50])
        if any(vals):
            print(vals)
PYEOF", "description": "Inspect all sheets in the workbook"}

