{"command": "python3 << 'PYEOF'
import json
import urllib.request

# Try IMF data for Georgia - using the values endpoint pattern
# NGDP_R - Real GDP level
url1 = "https://www.imf.org/external/datamapper/api/v1/NGDP_R/GEO?periods=2000,2001,2002,2003,2004,2005,2006,2007,2008,2009,2010,2011,2012,2013,2014,2015,2016,2017,2018,2019,2020,2021,2022,2023,2024,2025,2026,2027"
try:
    req = urllib.request.Request(url1, headers={'User-Agent': 'Mozilla/5.0'})
    with urllib.request.urlopen(req, timeout=30) as response:
        data = json.loads(response.read().decode())
        print("NGDP_R data keys:", data.keys() if isinstance(data, dict) else 'not dict')
        if 'values' in data and 'NGDP_R' in data['values'] and 'GEO' in data['values']['NGDP_R']:
            geo_data = data['values']['NGDP_R']['GEO']
            for year, val in sorted(geo_data.items()):
                print(f"{year}: {val}")
        else:
            print("Full response (first 2000 chars):", str(data)[:2000])
except Exception as e:
    print(f"Error: {e}")
PYEOF", "description": "Fetch Georgia NGDP_R values"}

