{"command": "python3 << 'PYEOF'
import openpyxl
wb = openpyxl.load_workbook('/root/pwt_data.xlsx')
ws = wb['Data']
# Find Georgia data for rgdpna (real GDP at constant 2017 national prices) and rnna
georgia_data = []
for row in ws.iter_rows(min_row=2, min_col=1, max_col=22):
    if row[1].value == 'Georgia':
        year = row[3].value
        rgdpna = row[18].value  # column 19 (0-indexed 18) = rgdpna
        rnna = row[21].value  # column 22 (0-indexed 21) = rnna
        georgia_data.append((year, rgdpna, rnna))

for year, rgdpna, rnna in georgia_data:
    if year >= 2000:
        print(f"{year}: rgdpna={rgdpna}, rnna={rnna}")
PYEOF", "description": "Extract Georgia rgdpna and rnna from PWT"}

